sql:
SELECT form_name, form_description 
FROM assessment_forms
WHERE form_id = 1;

SELECT student_id, first_name, last_name
FROM students
WHERE student_id NOT IN (SELECT student_id FROM assessment_results);

external_knowledge:
- 'top-tier students' refers to students who are in grades and classes that are above average;
- 'personal contact details' means the students' first name, last name, and email;
- 'grade information' includes the name of the grade level the student is in.

sql:
SELECT COUNT(*) 
FROM assessment_results 
WHERE raw_score < (SELECT AVG(raw_score) FROM assessment_results);

SELECT AVG(raw_score) 
FROM assessment_results 
WHERE assessment_id = 0;

external_knowledge:
- 'specific student' refers to student_id = 1;
- 'versions of the tests' refer to different forms identified by form_id;
- 'mistakes' are the incorrect questions counted per form.
